query:
{
  storageAccounts(
    where: {
      OR: [
        { blobServiceDeletePolicyEnabled: { eq: false } }
        { blobServiceDeletePolicyDays: { eq: 0 } }
        { containerDeleteRetentionPolicyEnabled: { eq: false } }
        { containerDeleteRetentionPolicyDays: { eq: 0 } }
      ]
    }
  ) {
    ...AssetFragment
  }
}
